// WeddingPage - Final Version
import React, { useState, useEffect } from 'react';
import './WeddingPage.css';
import { Church, Wine, Calendar, Phone, Mail, Heart } from 'lucide-react';
import heroBg from "../images/hero-bg.jpeg";
import confetti from 'canvas-confetti';

const WeddingPage = () => {
  const [countdown, setCountdown] = useState({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [activeFaq, setActiveFaq] = useState(null);
  const [showCalendarOptions, setShowCalendarOptions] = useState(false);

  // Countdown
  useEffect(() => {
    const updateCountdown = () => {
      const weddingDate = new Date('2027-04-24T17:00:00');
      const now = new Date();
      const diff = weddingDate - now;
      if (diff > 0) {
        const days = Math.floor(diff / (1000 * 60 * 60 * 24));
        const hours = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
        const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
        const seconds = Math.floor((diff % (1000 * 60)) / 1000);
        setCountdown({ days, hours, minutes, seconds });
      } else {
        setCountdown({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      }
    };
    updateCountdown();
    const interval = setInterval(updateCountdown, 1000);
    return () => clearInterval(interval);
  }, []);

  // Scroll animations
  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) entry.target.classList.add('visible');
      });
    }, { threshold: 0.1, rootMargin: '0px 0px -50px 0px' });
    document.querySelectorAll('.wedding-section').forEach(section => {
      section.classList.add('fade-in');
      observer.observe(section);
    });
    return () => observer.disconnect();
  }, []);

  // Calendar
  const handleCalendarClick = (type) => {
    const eventDetails = {
      title: 'Ślub Kinga & Michał',
      description: 'Zapraszamy na nasz ślub!',
      location: 'Plac Konfederacji 55, 01-834 Warszawa',
      startDate: '20270424T170000',
      endDate: '20270425T050000'
    };
    if (type === 'google') {
      const googleUrl = new URL('https://calendar.google.com/calendar/render');
      googleUrl.searchParams.append('action', 'TEMPLATE');
      googleUrl.searchParams.append('text', eventDetails.title);
      googleUrl.searchParams.append('details', eventDetails.description);
      googleUrl.searchParams.append('location', eventDetails.location);
      googleUrl.searchParams.append('dates', `${eventDetails.startDate}/${eventDetails.endDate}`);
      window.open(googleUrl.toString(), '_blank');
    } else if (type === 'apple') {
      const icsContent = generateICS(eventDetails);
      const blob = new Blob([icsContent], { type: 'text/calendar;charset=utf-8' });
      const link = document.createElement('a');
      link.href = window.URL.createObjectURL(blob);
      link.download = 'slub-kinga-michal.ics';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
    setShowCalendarOptions(false);
  };

  const generateICS = (eventDetails) => {
    const now = new Date();
    const timestamp = now.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';
    return [
      'BEGIN:VCALENDAR',
      'VERSION:2.0',
      'PRODID:-//Wedding Kinga & Michał//PL',
      'CALSCALE:GREGORIAN',
      'METHOD:PUBLISH',
      'X-WR-CALNAME:Ślub Kinga & Michał',
      'X-WR-TIMEZONE:Europe/Warsaw',
      'BEGIN:VEVENT',
      `UID:${timestamp}@wedding-kinga-michal`,
      `DTSTAMP:${timestamp}`,
      `DTSTART;TZID=Europe/Warsaw:${eventDetails.startDate}`,
      `DTEND;TZID=Europe/Warsaw:${eventDetails.endDate}`,
      `SUMMARY:${eventDetails.title}`,
      `DESCRIPTION:${eventDetails.description}`,
      `LOCATION:${eventDetails.location}`,
      'STATUS:CONFIRMED',
      'SEQUENCE:0',
      'TRANSP:OPAQUE',
      'BEGIN:VALARM',
      'TRIGGER:-P1D',
      'ACTION:DISPLAY',
      'DESCRIPTION:Przypomnienie: Jutro ślub Kingi i Michała!',
      'END:VALARM',
      'END:VEVENT',
      'END:VCALENDAR'
    ].join('\r\n');
  };

  const faqData = [
    { question: 'Czy ceremonia i wesele odbywają się w tym samym miejscu?', answer: 'Nie. Ceremonia w kościele, przyjęcie na obrzeżach Warszawy.' },
    { question: 'Czy będzie zapewniony transport między kościołem a salą?', answer: 'Nie organizujemy transportu zbiorowego. Można skorzystać z samochodu lub Ubera.' },
    { question: 'Czy można przyjść z osobą towarzyszącą?', answer: 'Jeśli zaproszenie przewiduje osobę towarzyszącą, oczywiście.' },
    { question: 'Czy dzieci są zaproszone?', answer: 'Tak, dzieci są mile widziane.' },
    { question: 'Czy będą poprawiny?', answer: 'Nie planujemy poprawin.' },
    { question: 'Jakie prezenty sprawią nam największą radość?', answer: 'Najwygodniejsza forma to koperta. Drobny upominek też mile widziany.' },
    { question: 'Czy zapewniamy nocleg dla gości?', answer: 'Nie organizujemy noclegów, ale w pobliżu są hotele.' },
    { question: 'Czy można zgłosić dietę specjalną?', answer: 'Tak, prosimy o informację przy potwierdzeniu obecności.' },
    { question: 'Do kiedy należy potwierdzić obecność?', answer: 'Do 1 marca 2027.' },
    { question: 'Czy na miejscu będzie parking?', answer: 'Tak, przy kościele i sali weselnej.' },
    { question: 'Czy można robić zdjęcia podczas ceremonii?', answer: 'Prosimy pozostawić fotografowanie naszemu fotografowi, później zdjęcia mile widziane.' }
  ];

  return (
    <div className="wedding-page">
      {/* Hero */}
      <section className="hero">
        <div className="hero-bg" style={{ backgroundImage: `url(${heroBg})` }}></div>
        <div className="hero-overlay"></div>
        <div className="hero-content">
          <h1 className="hero-names">Kinga & Michał</h1>
          <p className="hero-subtitle">Zapraszamy na nasz ślub</p>
          <div className="hero-date"><span>24</span>•<span>04</span>•<span>2027</span></div>
          <p className="hero-location">Warszawa</p>
        </div>
        <div className="scroll-indicator"><div className="scroll-arrow"></div></div>
      </section>

      {/* Welcome */}
      <section className="wedding-section welcome">
        <div className="container">
          <p className="welcome-text">Z radością zapraszamy Was do wspólnego świętowania najważniejszego dnia w naszym życiu.</p>
        </div>
      </section>

      {/* Countdown */}
      <section className="wedding-section countdown">
        <div className="container countdown-wrapper">
          {['days','hours','minutes','seconds'].map((unit,index)=>(
            <div className="countdown-item" key={unit}>
              <div className="countdown-number">{countdown[unit]}</div>
              <div className="countdown-label">{unit}</div>
            </div>
          ))}
        </div>
      </section>

      {/* Timeline */}
      <section className="wedding-section timeline">
        <div className="container timeline-wrapper">
          <div className="timeline-item">
            <div className="timeline-time">17:00</div>
            <div className="timeline-content">
              <div className="timeline-icon"><Church size={32} strokeWidth={1.5} /></div>
              <h3>Ceremonia Ślubna</h3>
              <p>Parafia pw. św. Zygmunta, Warszawa Bielany</p>
            </div>
          </div>
          <div className="timeline-item">
            <div className="timeline-time">19:00</div>
            <div className="timeline-content">
              <div className="timeline-icon"><Wine size={32} strokeWidth={1.5} /></div>
              <h3>Przyjęcie Weselne</h3>
              <p>Sala Weselna Ostoja, Warszawa</p>
            </div>
          </div>
        </div>
      </section>

      {/* Venues */}
      <section className="wedding-section venues">
        <div className="container venues-grid">
          {[
            {title:'Ceremonia Ślubna', location:'Parafia pw. św. Zygmunta', address:'Plac Konfederacji 55, 01-834 Warszawa', map:'https://maps.app.goo.gl/WXoWZUWh7tDLzjoy7'},
            {title:'Wesele', location:'Sala Weselna Ostoja', address:'Marmurowa 11, 03-053 Warszawa', map:'https://maps.app.goo.gl/xE75TjZVjaR63TvY9'}
          ].map((venue,index)=>(
            <div className="venue-card" key={index}>
              <h3>{venue.title}</h3>
              <div className="venue-info">
                <h4>{venue.location}</h4>
                <p>{venue.address}</p>
              </div>
              <a href={venue.map} target="_blank" rel="noopener noreferrer" className="btn btn-outline contact-hover">Nawiguj w Google Maps</a>
            </div>
          ))}
        </div>
      </section>

      {/* Save Date */}
      <section className="wedding-section save-date">
        <div className="container">
          <button className="btn btn-primary contact hover" onClick={()=>setShowCalendarOptions(!showCalendarOptions)}>
            <Calendar size={20} strokeWidth={2} /><span>Dodaj do kalendarza</span>
          </button>
          {showCalendarOptions && (
            <div className="calendar-options show">
              <button onClick={()=>handleCalendarClick('google')} className="calendar-option">Google Calendar</button>
              <button onClick={()=>handleCalendarClick('apple')} className="calendar-option">Apple Calendar</button>
            </div>
          )}
        </div>
      </section>

      {/* Quote */}
      <section className="wedding-section quote">
        <blockquote>„A więc trwają wiara, nadzieja i miłość – z nich zaś największa jest miłość."</blockquote>
        <div className="heart-decoration"><Heart size={32} strokeWidth={1.5} /></div>
      </section>

      {/* FAQ */}
      <section className="wedding-section faq">
        <div className="container faq-wrapper">
          {faqData.map((item,index)=>(
            <div className={`faq-item contact hover${activeFaq===index?' active':''}`} key={index}>
              <button className="faq-question" onClick={()=>setActiveFaq(activeFaq===index?null:index)}>
                {item.question}<span className="faq-toggle">+</span>
              </button>
              <div className="faq-answer"><p>{item.answer}</p></div>
            </div>
          ))}
        </div>
      </section>

      {/* Contact */}
      <section className="wedding-section contact">
        <div className="container contact-grid">
          {[
            {name:'Kinga', phone:'+48 507 562 811', email:'kingawojcik5252@gmail.com'},
            {name:'Michał', phone:'+48 511 779 350', email:'michalokozak@gmail.com'}
          ].map((person,index)=>(
            <div className="contact-person" key={index}>
              <h3>{person.name}</h3>
              <div className="contact-info">
                <div className="contact-item group"><Phone size={20} strokeWidth={1.5} /><a href={`tel:${person.phone}`}>{person.phone}</a></div>
                <div className="contact-item group"><Mail size={20} strokeWidth={1.5} /><a href={`mailto:${person.email}`}>{person.email}</a></div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Footer */}
      <footer className="footer">
        <p className="footer-quote" onMouseEnter={()=>confetti({ particleCount: 100, spread: 70 })}>Do zobaczenia!</p>
        <p className="footer-text">Kinga <Heart size={16} strokeWidth={2} className="footer-heart" /> Michał 2027</p>
      </footer>
    </div>
  );
};

export default WeddingPage;
